23	#include "mupdf/fitz.h"
24	
25	#include <zlib.h>
26	
27	#include <string.h>
28	
29	typedef struct
30	{
31		fz_stream *chain;
32		z_stream z;
33		unsigned char buffer[4096];
34	} fz_inflate_state;
35	
36	void *fz_zlib_alloc(void *ctx, unsigned int items, unsigned int size)
37	{
38		return Memento_label(fz_malloc_no_throw(ctx, (size_t)items * size), "zlib_alloc");
39	}
40	
41	void fz_zlib_free(void *ctx, void *ptr)
42	{
43		fz_free(ctx, ptr);
44	}
45	
46	static int
47	next_flated(fz_context *ctx, fz_stream *stm, size_t required)
48	{
49		fz_inflate_state *state = stm->state;
50		fz_stream *chain = state->chain;
51		z_streamp zp = &state->z;
52		int code;
53		unsigned char *outbuf = state->buffer;
54		int outlen = sizeof(state->buffer);
55	
56		if (stm->eof)
57			return EOF;
58	
59		zp->next_out = outbuf;
60		zp->avail_out = outlen;
61	
62		while (zp->avail_out > 0)
63		{
64			zp->avail_in = (uInt)fz_available(ctx, chain, 1);
65			zp->next_in = chain->rp;
66	
67			code = inflate(zp, Z_SYNC_FLUSH);
68	
69			chain->rp = chain->wp - zp->avail_in;
70	
71			if (code == Z_STREAM_END)
72			{
73				break;
74			}
75			else if (code == Z_BUF_ERROR)
76			{
77				fz_warn(ctx, "premature end of data in flate filter");
78				break;
79			}
80			else if (code == Z_DATA_ERROR && zp->avail_in == 0)
81			{
82				fz_warn(ctx, "ignoring zlib error: %s", zp->msg);
83				break;
84			}
85			else if (code == Z_DATA_ERROR && !strcmp(zp->msg, "incorrect data check"))
86			{
87				fz_warn(ctx, "ignoring zlib error: %s", zp->msg);
88				chain->rp = chain->wp;
89				break;
90			}
91			else if (code != Z_OK)
92			{
93				fz_throw(ctx, FZ_ERROR_LIBRARY, "zlib error: %s", zp->msg);
94			}
95		}
96	
97		stm->rp = state->buffer;
98		stm->wp = state->buffer + outlen - zp->avail_out;
99		stm->pos += outlen - zp->avail_out;
100		if (stm->rp == stm->wp)
101		{
102			stm->eof = 1;
103			return EOF;
104		}
105		return *stm->rp++;
106	}
107	
108	static void
109	close_flated(fz_context *ctx, void *state_)
110	{
111		fz_inflate_state *state = (fz_inflate_state *)state_;
112		int code;
113	
114		code = inflateEnd(&state->z);
115		if (code != Z_OK)
116			fz_warn(ctx, "zlib error: inflateEnd: %s", state->z.msg);
117	
118		fz_drop_stream(ctx, state->chain);
119		fz_free(ctx, state);
120	}
121	
122	fz_stream *
123	fz_open_flated(fz_context *ctx, fz_stream *chain, int window_bits)
124	{
125		fz_inflate_state *state;
126		int code;
127	
128		state = fz_malloc_struct(ctx, fz_inflate_state);
129		state->z.zalloc = fz_zlib_alloc;
130		state->z.zfree = fz_zlib_free;
131		state->z.opaque = ctx;
132		state->z.next_in = NULL;
133		state->z.avail_in = 0;
134	
135		code = inflateInit2(&state->z, window_bits);
136		if (code != Z_OK)
137		{
138			fz_free(ctx, state);
139			fz_throw(ctx, FZ_ERROR_LIBRARY, "zlib error: inflateInit2 failed");
140		}
141	
142		state->chain = fz_keep_stream(ctx, chain);
143	
144		return fz_new_stream(ctx, state, next_flated, close_flated);
145	}
