23	#include "mupdf/fitz.h"
24	
25	#include <stdio.h>
26	#include <jpeglib.h>
27	
28	#ifndef SHARE_JPEG
29	typedef void * backing_store_ptr;
30	#include "jmemcust.h"
31	#endif
32	
33	typedef struct
34	{
35		fz_stream *chain;
36		fz_stream *jpegtables;
37		fz_stream *curr_stm;
38		fz_context *ctx;
39		int color_transform;
40		int invert_cmyk; /* has inverted CMYK polarity */
41		int init;
42		int stride;
43		int l2factor;
44		unsigned char *scanline;
45		unsigned char *rp, *wp;
46		struct jpeg_decompress_struct cinfo;
47		struct jpeg_source_mgr srcmgr;
48		struct jpeg_error_mgr errmgr;
49		jmp_buf jb;
50		char msg[JMSG_LENGTH_MAX];
51	
52		unsigned char buffer[4096];
53	} fz_dctd;
54	
55	#ifdef SHARE_JPEG
56	
57	#define JZ_DCT_STATE_FROM_CINFO(c) (fz_dctd *)((c)->client_data)
58	
59	static void fz_dct_mem_init(struct jpeg_decompress_struct *cinfo, fz_dctd *state)
60	{
61		cinfo->client_data = state;
62	}
63	
64	#define fz_dct_mem_term(cinfo)
65	
66	#else /* SHARE_JPEG */
67	
68	#define JZ_DCT_STATE_FROM_CINFO(c) (fz_dctd *)(GET_CUST_MEM_DATA(c)->priv)
69	
70	static void *
71	fz_dct_mem_alloc(j_common_ptr cinfo, size_t size)
72	{
73		fz_dctd *state = JZ_DCT_STATE_FROM_CINFO(cinfo);
74		return Memento_label(fz_malloc_no_throw(state->ctx, size), "dct_alloc");
75	}
76	
77	static void *
78	fz_dct_mem_calloc(j_common_ptr cinfo, size_t size)
79	{
80		fz_dctd *state = JZ_DCT_STATE_FROM_CINFO(cinfo);
81		return Memento_label(fz_calloc_no_throw(state->ctx, 1, size), "dct_calloc");
82	}
83	
84	static void
85	fz_dct_mem_free(j_common_ptr cinfo, void *object, size_t size)
86	{
87		fz_dctd *state = JZ_DCT_STATE_FROM_CINFO(cinfo);
88		fz_free(state->ctx, object);
89	}
90	
91	static void
92	fz_dct_mem_init(struct jpeg_decompress_struct *cinfo, fz_dctd *state)
93	{
94		jpeg_cust_mem_data *custmptr;
95		custmptr = fz_malloc_struct(state->ctx, jpeg_cust_mem_data);
96		if (!jpeg_cust_mem_init(custmptr, (void *) state, NULL, NULL, NULL,
97					fz_dct_mem_alloc, fz_dct_mem_free,
98					fz_dct_mem_calloc, fz_dct_mem_free, NULL))
99		{
100			fz_free(state->ctx, custmptr);
101			fz_throw(state->ctx, FZ_ERROR_LIBRARY, "cannot initialize custom JPEG memory handler");
102		}
103		cinfo->client_data = custmptr;
104	}
105	
106	static void
107	fz_dct_mem_term(struct jpeg_decompress_struct *cinfo)
108	{
109		if (cinfo->client_data)
110		{
111			fz_dctd *state = JZ_DCT_STATE_FROM_CINFO(cinfo);
112			fz_free(state->ctx, cinfo->client_data);
113			cinfo->client_data = NULL;
114		}
115	}
116	
117	#endif /* SHARE_JPEG */
118	
119	static void error_exit_dct(j_common_ptr cinfo)
120	{
121		char msg[JMSG_LENGTH_MAX];
122		fz_dctd *state = JZ_DCT_STATE_FROM_CINFO(cinfo);
123		fz_context *ctx = state->ctx;
124		cinfo->err->format_message(cinfo, msg);
125		fz_throw(ctx, FZ_ERROR_LIBRARY, "jpeg error: %s", msg);
126	}
127	
128	static void output_message_dct(j_common_ptr cinfo)
129	{
130		/* swallow message */
131	}
132	
133	static void init_source_dct(j_decompress_ptr cinfo)
134	{
135		/* nothing to do */
136	}
137	
138	static void term_source_dct(j_decompress_ptr cinfo)
139	{
140		/* nothing to do */
141	}
142	
143	static boolean fill_input_buffer_dct(j_decompress_ptr cinfo)
144	{
145		static unsigned char eoi[2] = { 0xFF, JPEG_EOI };
146		struct jpeg_source_mgr *src = cinfo->src;
147		fz_dctd *state = JZ_DCT_STATE_FROM_CINFO(cinfo);
148		fz_context *ctx = state->ctx;
149		fz_stream *curr_stm = state->curr_stm;
150	
151		curr_stm->rp = curr_stm->wp;
152		fz_try(ctx)
153		{
154			src->bytes_in_buffer = fz_available(ctx, curr_stm, 1);
155		}
156		fz_catch(ctx)
157		{
158			/* Since fz_available swallows all other errors, the only errors that can
159			 * bubble up to here are TRYLATER and exception stack overflow.
160			 * Ignore this catastrophic failure and treat it as end of file.
161			 * NOTE: We do NOT handle TRYLATER here.
162			 */
163			src->next_input_byte = eoi;
164			src->bytes_in_buffer = 2;
165			return 1;
166		}
167	
168		src->next_input_byte = curr_stm->rp;
169	
170		if (src->bytes_in_buffer == 0)
171		{
172			fz_warn(state->ctx, "premature end of file in jpeg");
173			src->next_input_byte = eoi;
174			src->bytes_in_buffer = 2;
175		}
176	
177		return 1;
178	}
179	
180	static void skip_input_data_dct(j_decompress_ptr cinfo, long num_bytes)
181	{
182		struct jpeg_source_mgr *src = cinfo->src;
183		if (num_bytes > 0)
184		{
185			while ((size_t)num_bytes > src->bytes_in_buffer)
186			{
187				num_bytes -= (long)src->bytes_in_buffer;
188				(void) src->fill_input_buffer(cinfo);
189			}
190			src->next_input_byte += num_bytes;
191			src->bytes_in_buffer -= num_bytes;
192		}
193	}
194	
195	/* Invert CMYK polarity if it is a standalone JPEG file.
196	 * For JPEG images embedded in PDF files, the CMYK data is normal.
197	 * For JPEG images created by Photoshop, the CMYK data is inverted.
198	 */
199	static void invert_cmyk(unsigned char *p, int n)
200	{
201		int i;
202		for (i = 0; i < n; ++i)
203			p[i] = 255 - p[i];
204	}
205	
206	static int
207	next_dctd(fz_context *ctx, fz_stream *stm, size_t max)
208	{
209		fz_dctd *state = stm->state;
210		j_decompress_ptr cinfo = &state->cinfo;
211		unsigned char *p = state->buffer;
212		unsigned char *ep;
213		size_t n;
214		int c;
215	
216		if (max > sizeof(state->buffer))
217			max = sizeof(state->buffer);
218		ep = state->buffer + max;
219	
220		fz_try(ctx)
221		{
222			if (!state->init)
223			{
224				state->init = 1;
225	
226				/* Skip over any stray whitespace at the start of the stream */
227				while ((c = fz_peek_byte(ctx, state->chain)) == '\n' || c == '\r' || c == ' ')
228					(void)fz_read_byte(ctx, state->chain);
229	
230				jpeg_create_decompress(cinfo);
231	
232				cinfo->src = &state->srcmgr;
233				cinfo->src->init_source = init_source_dct;
234				cinfo->src->fill_input_buffer = fill_input_buffer_dct;
235				cinfo->src->skip_input_data = skip_input_data_dct;
236				cinfo->src->resync_to_restart = jpeg_resync_to_restart;
237				cinfo->src->term_source = term_source_dct;
238	
239				/* optionally load additional JPEG tables first */
240				if (state->jpegtables)
241				{
242					state->curr_stm = state->jpegtables;
243					cinfo->src->next_input_byte = state->curr_stm->rp;
244					cinfo->src->bytes_in_buffer = state->curr_stm->wp - state->curr_stm->rp;
245					jpeg_read_header(cinfo, 0);
246					state->curr_stm->rp = state->curr_stm->wp - state->cinfo.src->bytes_in_buffer;
247					state->curr_stm = state->chain;
248				}
249	
250				cinfo->src->next_input_byte = state->curr_stm->rp;
251				cinfo->src->bytes_in_buffer = state->curr_stm->wp - state->curr_stm->rp;
252	
253				jpeg_read_header(cinfo, 1);
254	
255				/* default value is 1 if the image has components and 0 otherwise */
256				if (state->color_transform < 0)
257				{
258					if (cinfo->num_components == 3)
259						state->color_transform = 1;
260					else
261						state->color_transform = 0;
262				}
263	
264				/* Adobe APP marker overrides ColorTransform from PDF */
265				if (cinfo->saw_Adobe_marker)
266					state->color_transform = cinfo->Adobe_transform;
267	
268				/* Disable JPEG color transformations if ColorTransform is 0.
269				 * This is usually handled by libjpeg, but since PDF can override
270				 * the default behavior if the Adobe APP marker is missing
271				 * we must do it here as well.
272				 */
273				if (state->color_transform == 0)
274				{
275					if (cinfo->num_components == 3)
276						cinfo->jpeg_color_space = JCS_RGB;
277					if (cinfo->num_components == 4)
278						cinfo->jpeg_color_space = JCS_CMYK;
279				}
280	
281				cinfo->scale_num = 8/(1<<state->l2factor);
282				cinfo->scale_denom = 8;
283	
284				jpeg_start_decompress(cinfo);
285	
286				state->stride = cinfo->output_width * cinfo->output_components;
287				state->scanline = Memento_label(fz_malloc(ctx, state->stride), "dct_scanline");
288				state->rp = state->scanline;
289				state->wp = state->scanline;
290			}
291	
292			n = fz_minz(state->wp - state->rp, ep - p);
293			if (n > 0)
294			{
295				memcpy(p, state->rp, n);
296				p += n;
297				state->rp += n;
298			}
299	
300			while (p < ep)
301			{
302				if (cinfo->output_scanline == cinfo->output_height)
303					break;
304	
305				if (p + state->stride <= ep)
306				{
307					jpeg_read_scanlines(cinfo, &p, 1);
308					if (state->invert_cmyk && cinfo->num_components == 4)
309						invert_cmyk(p, state->stride);
310					p += state->stride;
311				}
312				else
313				{
314					jpeg_read_scanlines(cinfo, &state->scanline, 1);
315					if (state->invert_cmyk && cinfo->num_components == 4)
316						invert_cmyk(state->scanline, state->stride);
317					state->rp = state->scanline;
318					state->wp = state->scanline + state->stride;
319				}
320	
321				n = fz_minz(state->wp - state->rp, ep - p);
322				if (n > 0)
323				{
324					memcpy(p, state->rp, n);
325					p += n;
326					state->rp += n;
327				}
328			}
329			stm->rp = state->buffer;
330			stm->wp = p;
331			stm->pos += (p - state->buffer);
332		}
333		fz_catch(ctx)
334		{
335			if (cinfo->src)
336				state->curr_stm->rp = state->curr_stm->wp - cinfo->src->bytes_in_buffer;
337			fz_rethrow(ctx);
338		}
339	
340		if (p == stm->rp)
341			return EOF;
342	
343		return *stm->rp++;
344	}
345	
346	static void
347	close_dctd(fz_context *ctx, void *state_)
348	{
349		fz_dctd *state = (fz_dctd *)state_;
350	
351		if (state->init)
352		{
353			/* We call jpeg_abort rather than the more usual
354			 * jpeg_finish_decompress here. This has the same effect,
355			 * but doesn't spew warnings if we didn't read enough data etc.
356			 * Annoyingly jpeg_abort can throw
357			 */
358			fz_try(ctx)
359				jpeg_abort((j_common_ptr)&state->cinfo);
360			fz_catch(ctx)
361			{
362				/* Ignore any errors here */
363			}
364	
365			jpeg_destroy_decompress(&state->cinfo);
366		}
367	
368		fz_dct_mem_term(&state->cinfo);
369	
370		if (state->cinfo.src)
371			state->curr_stm->rp = state->curr_stm->wp - state->cinfo.src->bytes_in_buffer;
372	
373		fz_free(ctx, state->scanline);
374		fz_drop_stream(ctx, state->chain);
375		fz_drop_stream(ctx, state->jpegtables);
376		fz_free(ctx, state);
377	}
378	
379	fz_stream *
380	fz_open_dctd(fz_context *ctx, fz_stream *chain, int color_transform, int invert_cmyk, int l2factor, fz_stream *jpegtables)
381	{
382		fz_dctd *state = fz_malloc_struct(ctx, fz_dctd);
383		j_decompress_ptr cinfo = &state->cinfo;
384	
385		state->ctx = ctx;
386	
387		fz_try(ctx)
388			fz_dct_mem_init(cinfo, state);
389		fz_catch(ctx)
390		{
391			fz_free(ctx, state);
392			fz_rethrow(ctx);
393		}
394	
395		state->color_transform = color_transform;
396		state->invert_cmyk = invert_cmyk;
397		state->init = 0;
398		state->l2factor = l2factor;
399		state->chain = fz_keep_stream(ctx, chain);
400		state->jpegtables = fz_keep_stream(ctx, jpegtables);
401		state->curr_stm = state->chain;
402	
403		cinfo->src = NULL;
404		cinfo->err = &state->errmgr;
405		jpeg_std_error(cinfo->err);
406		cinfo->err->output_message = output_message_dct;
407		cinfo->err->error_exit = error_exit_dct;
408	
409		return fz_new_stream(ctx, state, next_dctd, close_dctd);
410	}
